mapper.select:
select p.id,
p.name,
p.business_id,
p.category_id,
pc.name categoryName,
p.description,
p.price,
p.stock,
p.sales,
p.status,
p.updated_time,
(select round(avg(br.score), 1) from business_rating br where br.product_id = p.id) rating
from product p
left join product_category pc on p.category_id = pc.id



        and p.name like concat('%',#{dto.name},'%') collate utf8mb4_general_ci



        and p.status = #{dto.status}



        and p.category_id = #{dto.categoryId}



        and p.price >= #{dto.minPrice}


        and p.price <= #{dto.maxPrice}



        and p.business_id = #{dto.businessId}




    order by p.sales ${dto.salesSort}


    order by p.stock ${dto.stockSort}

select p.id, p.name, p.business_id, p.category_id, p.description, p.price, p.sales, (select round(avg(br.score), 1) from business_rating br where br.product_id = p.id) rating from product p left join product_category pc on p.category_id = pc.id
and p.name like concat('%',#{dto.name},'%') collate utf8mb4_general_ci
and p.price >= #{dto.minPrice}
and p.price <= #{dto.maxPrice}
order by p.sales ${dto.salesSort}
